#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int countUniqueEmailGroups(vector<string>& emails) {
        unordered_set<string> st;
        for (string email : emails) {
            size_t atPos = email.find('@');
            string local = email.substr(0, atPos);
            string domain = email.substr(atPos + 1);
            transform(domain.begin(), domain.end(), domain.begin(), ::tolower);
            transform(local.begin(), local.end(), local.begin(), ::tolower);
            size_t plusPos = local.find('+');
            if (plusPos != string::npos) {
                local = local.substr(0, plusPos);
            }
            local.erase(remove(local.begin(), local.end(), '.'), local.end());
            st.insert(local + "@" + domain);
        }
        return st.size();
    }
};

