    def countUniqueEmailGroups(self, emails):
        st = set()
        for email in emails:
            local, domain = email.split('@', 1)
            domain = domain.lower()
            local = local.lower()
            plus = local.find('+')
            if plus != -1:
                local = local[:plus]
            local = local.replace('.', '')
            st.add(local + '@' + domain)
        return len(st)

