#include <bits/stdc++.h>
using namespace std;

class solution {
public:
    int calculateTypingDistance(string text) {
        unordered_map<char, pair<int, int>> pos;

        string row0 = "qwertyuiop";
        string row1 = "asdfghjkl";
        string row2 = "zxcvbnm";

        for (int c = 0; c < row0.size(); ++c) {
            pos[row0[c]] = {0, c};
        }
        for (int c = 0; c < row1.size(); ++c) {
            pos[row1[c]] = {1, c};
        }
        for (int c = 0; c < row2.size(); ++c) {
            pos[row2[c]] = {2, c};
        }

        int ans = 0;
        char cur = 'a';

        for (char ch : text) {
            pair<int,int> p1 = pos[cur];
            pair<int,int> p2 = pos[ch];

            int r1 = p1.first;
            int c1 = p1.second;
            int r2 = p2.first;
            int c2 = p2.second;

            ans += abs(r1 - r2) + abs(c1 - c2);
            cur = ch;
        }

        return ans;
    }
};

